// Get input data and configuration
const raw = $('Receive Data').first().json.body || $('Receive Data').first().json;
const config = $('Configure Field Mapping').first().json;

const mappings = config.fieldMappings || [];
const settings = config.globalSettings || {};

// Extract records — support both { records: [...] } and single object
let records = [];
if (raw.records && Array.isArray(raw.records)) {
  records = raw.records;
} else if (Array.isArray(raw)) {
  records = raw;
} else {
  // Single object: wrap in array, exclude meta fields
  const single = {};
  for (const [k, v] of Object.entries(raw)) {
    if (k !== 'records') single[k] = v;
  }
  records = [single];
}

if (records.length === 0) {
  return [{
    json: {
      success: false,
      totalRecords: 0,
      validRecords: 0,
      errorCount: 1,
      records: [],
      errors: ['No records found in input data']
    }
  }];
}

const allErrors = [];
const transformedRecords = [];

// --- Helper: parse date from input format to output format ---
function parseDate(value, inputFormat, outputFormat) {
  if (!value || String(value).trim() === '') return null;
  const v = String(value).trim();

  // Build regex from input format
  const parts = inputFormat.split(/[.\-\/]/);
  const sep = inputFormat.match(/[.\-\/]/)?.[0] || '.';
  const valueParts = v.split(sep);

  if (valueParts.length !== parts.length) return null;

  let day, month, year;
  parts.forEach((p, i) => {
    const upper = p.toUpperCase();
    if (upper.startsWith('D')) day = parseInt(valueParts[i], 10);
    else if (upper.startsWith('M')) month = parseInt(valueParts[i], 10);
    else if (upper.startsWith('Y')) year = parseInt(valueParts[i], 10);
  });

  if (!day || !month || !year) return null;
  if (month < 1 || month > 12 || day < 1 || day > 31) return null;

  // Build output
  const pad = (n) => String(n).padStart(2, '0');
  return outputFormat
    .replace('YYYY', String(year))
    .replace('MM', pad(month))
    .replace('DD', pad(day));
}

// --- Helper: parse number with configurable decimal separator ---
function parseNumber(value, decSep) {
  if (value === null || value === undefined) return null;
  let v = String(value).trim();
  if (v === '') return null;

  // Remove thousands separators
  if (decSep === ',') {
    v = v.replace(/\./g, ''); // remove dots (thousands)
    v = v.replace(',', '.');  // comma to dot
  } else {
    v = v.replace(/,/g, ''); // remove commas (thousands)
  }

  const num = Number(v);
  return isNaN(num) ? null : num;
}

// --- Helper: parse boolean ---
function parseBoolean(value) {
  if (value === null || value === undefined) return null;
  const v = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'ja', 'y', 'j', 'aktiv', 'active', 'on'].includes(v)) return true;
  if (['false', '0', 'no', 'nein', 'n', 'inaktiv', 'inactive', 'off'].includes(v)) return false;
  return null;
}

// --- Process each record ---
records.forEach((record, rowIndex) => {
  const rowNum = rowIndex + 1;
  const transformed = {};
  const rowErrors = [];

  // Apply each mapping
  mappings.forEach((mapping) => {
    const { sourceField, targetField, dataType, defaultValue, required } = mapping;
    let value = record[sourceField];

    // Trim strings
    if (settings.trimStrings && typeof value === 'string') {
      value = value.trim();
    }

    // Empty string to null
    if (settings.emptyStringToNull && value === '') {
      value = null;
    }

    // Apply default if empty/null/undefined
    if ((value === null || value === undefined || value === '') && defaultValue !== undefined && defaultValue !== '') {
      value = defaultValue;
    }

    // Check required
    if (required && (value === null || value === undefined || value === '')) {
      rowErrors.push(`Row ${rowNum}: '${targetField}' is required but empty`);
      transformed[targetField] = null;
      return;
    }

    // Type conversion
    if (value !== null && value !== undefined && value !== '') {
      switch (dataType) {
        case 'number': {
          const num = parseNumber(value, settings.decimalSeparator || ',');
          if (num === null) {
            rowErrors.push(`Row ${rowNum}: '${targetField}' could not be converted to number (value: '${value}')`);
            value = null;
          } else {
            value = num;
          }
          break;
        }
        case 'boolean': {
          const bool = parseBoolean(value);
          if (bool === null) {
            rowErrors.push(`Row ${rowNum}: '${targetField}' could not be converted to boolean (value: '${value}')`);
            value = null;
          } else {
            value = bool;
          }
          break;
        }
        case 'date': {
          const inputFmt = settings.dateInputFormat || 'DD.MM.YYYY';
          const outputFmt = settings.dateOutputFormat || 'YYYY-MM-DD';
          const parsed = parseDate(value, inputFmt, outputFmt);
          if (parsed === null) {
            rowErrors.push(`Row ${rowNum}: '${targetField}' could not be parsed as date (value: '${value}', expected: '${inputFmt}')`);
            value = null;
          } else {
            value = parsed;
          }
          break;
        }
        case 'string':
          value = String(value);
          break;
        // 'auto' — keep as-is
      }
    }

    transformed[targetField] = value;
  });

  // Optionally keep unmapped fields
  if (!settings.removeUnmappedFields) {
    const mappedSourceFields = mappings.map(m => m.sourceField);
    for (const [key, val] of Object.entries(record)) {
      if (!mappedSourceFields.includes(key)) {
        transformed[key] = val;
      }
    }
  }

  transformedRecords.push(transformed);
  allErrors.push(...rowErrors);
});

const errorCount = allErrors.length;
const validRecords = records.length - new Set(allErrors.map(e => {
  const match = e.match(/Row (\d+):/);
  return match ? parseInt(match[1]) : null;
})).size;

return [{
  json: {
    success: errorCount === 0,
    totalRecords: records.length,
    validRecords,
    errorCount,
    records: transformedRecords,
    errors: allErrors
  }
}];
